pageProps.query:
    query eventQuery($relativePath: String!) {
  ...LayoutQueryFragment
  event(relativePath: $relativePath) {
    ...EventParts
  }
}

    fragment LayoutQueryFragment on Query {
  global(relativePath: "index.json") {
    ...GlobalParts
  }
}

    fragment GlobalParts on Global {
  header {
    __typename
    icon
    color
    nav {
      __typename
      href
      label
    }
  }
}


    fragment EventParts on Event {
  title
  date
  blocks {
    __typename
    ... on EventBlocksBroughtToYouBy {
      largeText
    }
    ... on EventBlocksEventTicket {
      heading
    }
    ... on EventBlocksHr {
      icon
    }
    ... on EventBlocksHowItWorks {
      heading
      items {
        __typename
        icon
        title
        text
      }
    }
    ... on EventBlocksContent {
      body
    }
    ... on EventBlocksTestimonials {
      heading
      logos {
        __typename
        src
        alt
        width
        height
      }
      quotes {
        __typename
        quote
        author
        jobTitle
      }
    }
  }
}
